VALUES
  ('diplomatic-4dfbb1fb-moex-00202', 'diplomatic-4dfbb1fb', 'diplomatic-4dfbb1fb-moex-113-c655adf3', 'sub-diplomatic-4dfbb1fb-05', NULL, 'single_choice', '關於我國憲法之權力分立原則，下列敘述何者正確？', '["總統不得發布任何替代或變更法律效力之命令，以免侵犯立法權", "立法院不得制定僅適用單一或少數對象之特殊類型法律，以免侵犯行政權", "行政院不得設置任何行政法院，以免侵犯司法權", "法院不得掌理審判及強制執行以外之事項，以免侵犯行政權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:41+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-義大利文組"}'::jsonb, NULL),
  ('diplomatic-4dfbb1fb-moex-00203', 'diplomatic-4dfbb1fb', 'diplomatic-4dfbb1fb-moex-113-c655adf3', 'sub-diplomatic-4dfbb1fb-05', NULL, 'single_choice', '關於政府採購得標廠商員工逾百者應進用一定比例原住民，未進用者令繳代金之規定，依司法院解釋 之意旨，下列敘述何者錯誤？', '["得標廠商於履約期間須進用一定比例之原住民，其營業自由因此受到限制", "得標廠商未達進用原住民之標準者須繳納代金，其財產權因此受到限制", "此規定於政府採購市場形成對於規模大小不同企業之差別待遇", "得標廠商於履約期間所能提供者多屬短期或不具技術性之工作，此規定難以達到增進原住民長期就 業之目的，違背比例原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:41+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-義大利文組"}'::jsonb, NULL),
